@namespace Lumeo

<button type="button" aria-pressed="@Pressed.ToString().ToLower()" aria-label="@AriaLabel" data-state="@(Pressed ? "on" : "off")" data-disabled="@(Disabled ? string.Empty : null)" class="@CssClass" @onclick="HandleToggle" disabled="@Disabled" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    /// <summary>The toggle's content (label text and/or icon).</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Whether the toggle is pressed (on). Two-way bindable via <see cref="PressedChanged"/>.</summary>
    [Parameter] public bool Pressed { get; set; }
    /// <summary>Raised when the toggle is clicked and its pressed state flips.</summary>
    [Parameter] public EventCallback<bool> PressedChanged { get; set; }
    /// <summary>Visual style: <see cref="ToggleVariant.Default"/> (borderless) or <see cref="ToggleVariant.Outline"/> (bordered).</summary>
    [Parameter] public ToggleVariant Variant { get; set; } = ToggleVariant.Default;
    /// <summary>Controls the toggle's height and horizontal padding. Default <see cref="Lumeo.Size.Md"/>.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    /// <summary>Per-toggle density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Only height + horizontal
    /// padding shift — text size + radius stay governed by <see cref="Size"/>.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    /// <summary>Disables the toggle, preventing clicks and dimming its appearance.</summary>
    [Parameter] public bool Disabled { get; set; }
    /// <summary>
    /// Accessible name exposed via <c>aria-label</c>. Required when
    /// <see cref="ChildContent"/> is an icon only (no visible text) — otherwise
    /// screen readers announce the toggle as an unnamed button.
    /// </summary>
    [Parameter] public string? AriaLabel { get; set; }
    /// <summary>Additional CSS classes merged onto the <c>&lt;button&gt;</c> element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Captures any unmatched attributes and applies them to the <c>&lt;button&gt;</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(VariantClasses, SizeClasses, BaseClasses, Class);

    private const string BaseClasses = "inline-flex items-center justify-center rounded-md text-sm font-medium cursor-pointer transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed";

    private string VariantClasses => (Variant, Pressed) switch
    {
        (ToggleVariant.Default, true) => "bg-accent text-accent-foreground",
        (ToggleVariant.Default, false) => "bg-transparent hover:bg-muted hover:text-muted-foreground",
        (ToggleVariant.Outline, true) => "bg-accent text-accent-foreground border border-input",
        (ToggleVariant.Outline, false) => "border border-input bg-transparent hover:bg-accent hover:text-accent-foreground",
        _ => ""
    };

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    // Height + horizontal padding track Size x Density; Comfortable
    // reproduces the historical per-Size values verbatim.
    private string SizeClasses => (Size, EffectiveDensity) switch
    {
        (Lumeo.Size.Sm, Lumeo.Density.Compact)  => "h-7 px-1.5",
        (Lumeo.Size.Sm, Lumeo.Density.Spacious) => "h-9 px-3",
        (Lumeo.Size.Sm, _)                      => "h-8 px-2",
        (Lumeo.Size.Lg, Lumeo.Density.Compact)  => "h-9 px-3",
        (Lumeo.Size.Lg, Lumeo.Density.Spacious) => "h-12 px-5",
        (Lumeo.Size.Lg, _)                      => "h-10 px-4",
        (_, Lumeo.Density.Compact)              => "h-8 px-2",
        (_, Lumeo.Density.Spacious)             => "h-11 px-4",
        _                                       => "h-9 px-3"
    };

    private async Task HandleToggle()
    {
        if (!Disabled)
        {
            Pressed = !Pressed;
            await PressedChanged.InvokeAsync(Pressed);
        }
    }

    public enum ToggleVariant { Default, Outline }
}
